import { useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import { LogOut, Bell, Search, Moon, Sun } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const Navbar = ({ toggleDarkMode, isDark }) => {
  const { user, logout } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logout();
    navigate('/login');
  };

  return (
    <header className="h-16 border-b border-border bg-background/80 backdrop-blur-md sticky top-0 z-40 flex items-center justify-between px-6 transition-colors">
      <div className="flex items-center gap-4 flex-1">
        <div className="relative w-full max-w-sm hidden md:block">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground h-4 w-4" />
          <input 
            type="text" 
            placeholder="Search..." 
            className="w-full bg-muted border-none rounded-full h-10 pl-10 pr-4 text-sm focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all placeholder:text-muted-foreground"
          />
        </div>
      </div>

      <div className="flex items-center gap-4">
        <button className="p-2 text-muted-foreground hover:bg-muted rounded-full transition-colors relative">
           <Bell size={20} />
           <span className="absolute top-1.5 right-1.5 w-2 h-2 rounded-full bg-red-500 border border-background"></span>
        </button>

        <button 
          onClick={toggleDarkMode} 
          className="p-2 text-muted-foreground hover:bg-muted rounded-full transition-colors"
        >
           {isDark ? <Sun size={20} /> : <Moon size={20} />}
        </button>

        <div className="h-8 w-px bg-border mx-1"></div>

        <button 
          onClick={handleLogout}
          className="flex items-center gap-2 text-sm font-medium text-red-500 hover:bg-red-500/10 px-3 py-2 rounded-lg transition-colors"
        >
          <LogOut size={18} />
          <span className="hidden sm:inline">Logout</span>
        </button>
      </div>
    </header>
  );
};

export default Navbar;

import { useState, useContext } from 'react';
import { NavLink } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Building2, Users, AlertCircle, CalendarClock, 
  Wallet, ShieldCheck, Wrench, LayoutDashboard, ChevronLeft, ChevronRight 
} from 'lucide-react';
import { AuthContext } from '../context/AuthContext';
import clsx from 'clsx';
import { twMerge } from 'tailwind-merge';

const roleLinks = {
  Super_Admin: [
    { name: 'Dashboard', path: '/dashboard', icon: LayoutDashboard },
    { name: 'Societies', path: '/societies', icon: Building2 },
  ],
  Society_Admin: [
    { name: 'Dashboard', path: '/dashboard', icon: LayoutDashboard },
    { name: 'Residents', path: '/residents', icon: Users },
    { name: 'Complaints', path: '/complaints', icon: AlertCircle },
    { name: 'Billing', path: '/billing', icon: Wallet },
    { name: 'Visitors', path: '/visitors', icon: ShieldCheck },
    { name: 'Vendors', path: '/vendors', icon: Wrench },
  ],
  Resident: [
    { name: 'Dashboard', path: '/dashboard', icon: LayoutDashboard },
    { name: 'Complaints', path: '/complaints', icon: AlertCircle },
    { name: 'My Bills', path: '/billing', icon: Wallet },
    { name: 'Visitors', path: '/visitors', icon: ShieldCheck },
  ],
  Security_Guard: [
    { name: 'Dashboard', path: '/dashboard', icon: LayoutDashboard },
    { name: 'Visitors', path: '/visitors', icon: ShieldCheck },
  ],
  Vendor: [
    { name: 'Dashboard', path: '/dashboard', icon: LayoutDashboard },
    { name: 'My Tasks', path: '/complaints', icon: Wrench },
  ]
};

const Sidebar = ({ isOpen, toggle }) => {
  const { user } = useContext(AuthContext);
  const links = user ? roleLinks[user.role] : [];

  return (
    <motion.div 
      animate={{ width: isOpen ? 256 : 80 }}
      className="h-screen bg-background border-r border-border flex flex-col justify-between sticky top-0 z-50 text-foreground transition-all duration-300"
    >
      <div>
        <div className="h-16 flex items-center justify-between px-4 border-b border-border">
          <AnimatePresence>
            {isOpen && (
              <motion.span 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="font-bold text-xl tracking-tight bg-gradient-to-r from-primary to-purple-500 bg-clip-text text-transparent"
              >
                SSMS
              </motion.span>
            )}
          </AnimatePresence>
          <button onClick={toggle} className="p-1 rounded-md hover:bg-muted text-muted-foreground hover:text-foreground">
            {isOpen ? <ChevronLeft size={20} /> : <ChevronRight size={20} />}
          </button>
        </div>

        <nav className="p-4 space-y-2">
          {links.map((link) => (
            <NavLink
              key={link.name}
              to={link.path}
              className={({ isActive }) => twMerge(clsx(
                "flex items-center gap-4 px-3 py-2.5 rounded-xl transition-all duration-200 group",
                isActive 
                  ? "bg-primary/10 text-primary shadow-sm" 
                  : "text-muted-foreground hover:bg-muted hover:text-foreground"
              ))}
            >
              <link.icon size={22} className={isOpen ? "" : "mx-auto"} />
              <AnimatePresence>
                {isOpen && (
                  <motion.span 
                    initial={{ opacity: 0, x: -10 }} 
                    animate={{ opacity: 1, x: 0 }} 
                    exit={{ opacity: 0, x: -10 }}
                    transition={{ duration: 0.2 }}
                    className="font-medium whitespace-nowrap"
                  >
                    {link.name}
                  </motion.span>
                )}
              </AnimatePresence>
            </NavLink>
          ))}
        </nav>
      </div>

      <div className="p-4 border-t border-border">
         <div className="flex items-center gap-3">
             <div className="h-10 w-10 shrink-0 rounded-full bg-primary/20 flex items-center justify-center text-primary font-bold">
                 {user?.name?.charAt(0) || 'U'}
             </div>
             {isOpen && (
                 <div className="flex flex-col overflow-hidden">
                     <span className="text-sm font-medium truncate">{user?.name}</span>
                     <span className="text-xs text-muted-foreground truncate">{user?.role?.replace('_', ' ')}</span>
                 </div>
             )}
         </div>
      </div>
    </motion.div>
  );
};

export default Sidebar;

import { createContext, useState, useEffect } from 'react';
import api from '../utils/api';

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const checkUser = async () => {
      try {
        const { data } = await api.get('/auth/profile');
        setUser(data);
      } catch (error) {
        setUser(null);
      } finally {
        setLoading(false);
      }
    };
    checkUser();
  }, []);

  const login = async (credentials) => {
    const { data } = await api.post('/auth/login', credentials);
    setUser(data);
    return data;
  };

  const register = async (userData) => {
    const { data } = await api.post('/auth/register', userData);
    setUser(data);
    return data;
  };

  const logout = async () => {
    await api.post('/auth/logout');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, register, logout, loading }}>
      {!loading && children}
    </AuthContext.Provider>
  );
};

import { useState, useContext, useEffect } from 'react';
import { Navigate, Outlet } from 'react-router-dom';
import Sidebar from '../components/Sidebar';
import Navbar from '../components/Navbar';
import { AuthContext } from '../context/AuthContext';
import { motion } from 'framer-motion';

const DashboardLayout = () => {
  const { user, loading } = useContext(AuthContext);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [isDark, setIsDark] = useState(() => {
    return document.documentElement.classList.contains('dark');
  });

  useEffect(() => {
    if (isDark) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDark]);

  if (loading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-background text-foreground">
        <div className="w-8 h-8 rounded-full border-4 border-primary border-t-transparent animate-spin"></div>
      </div>
    );
  }

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  return (
    <div className="flex bg-background min-h-screen text-foreground transition-colors duration-300">
      <Sidebar isOpen={sidebarOpen} toggle={() => setSidebarOpen(!sidebarOpen)} />

      <div className="flex-1 flex flex-col min-w-0">
        <Navbar toggleDarkMode={() => setIsDark(!isDark)} isDark={isDark} />

        <main className="flex-1 overflow-x-hidden overflow-y-auto bg-muted/20 p-6">
          {/* Framer motion page transitions */}
          <motion.div
            initial={{ opacity: 0, y: 15 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -15 }}
            transition={{ duration: 0.3 }}
            className="mx-auto max-w-7xl h-full"
          >
            <Outlet />
          </motion.div>
        </main>
      </div>
    </div>
  );
};

export default DashboardLayout;

import { useState, useContext } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { Shield, Users, Wrench, Building2, Crown, Loader2 } from 'lucide-react';

const roles = [
  { id: 'Resident', icon: Users, label: 'Resident', color: 'text-blue-500', bg: 'bg-blue-500/10', border: 'hover:border-blue-500' },
  { id: 'Society_Admin', icon: Building2, label: 'Society Admin', color: 'text-purple-500', bg: 'bg-purple-500/10', border: 'hover:border-purple-500' },
  { id: 'Security_Guard', icon: Shield, label: 'Security Guard', color: 'text-green-500', bg: 'bg-green-500/10', border: 'hover:border-green-500' },
  { id: 'Vendor', icon: Wrench, label: 'Vendor', color: 'text-orange-500', bg: 'bg-orange-500/10', border: 'hover:border-orange-500' },
  { id: 'Super_Admin', icon: Crown, label: 'Super Admin', color: 'text-red-500', bg: 'bg-red-500/10', border: 'hover:border-red-500' },
];

const Login = () => {
  const [selectedRole, setSelectedRole] = useState(null);
  const [credentials, setCredentials] = useState({ email: '', password: '', tenantId: '' });
  const [error, setError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleRoleSelect = (roleId) => {
    setSelectedRole(roleId);
    setError('');
  };

  const handleChange = (e) => {
    setCredentials({ ...credentials, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setIsSubmitting(true);

    try {
      await login({ ...credentials, role: selectedRole });
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-background p-4 relative overflow-hidden">
      {/* Background elements */}
      <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-primary/10 rounded-full blur-[100px] -z-10" />
      <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-purple-500/10 rounded-full blur-[100px] -z-10" />

      <motion.div 
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="w-full max-w-md"
      >
        <div className="text-center mb-8">
          <h1 className="text-3xl font-extrabold tracking-tight mb-2">Welcome Back</h1>
          <p className="text-muted-foreground">Log in to your SSMS account</p>
        </div>

        <div className="bg-card border border-border p-8 rounded-2xl shadow-xl glass relative">

          <AnimatePresence mode="wait">
            {!selectedRole ? (
              <motion.div
                key="role-selector"
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: 20 }}
                className="space-y-4"
              >
                <h3 className="text-sm font-medium text-muted-foreground mb-4 uppercase tracking-wider text-center">Select your role</h3>
                <div className="grid grid-cols-2 gap-3">
                  {roles.slice(0, 4).map((r) => (
                    <button
                      key={r.id}
                      onClick={() => handleRoleSelect(r.id)}
                      className={`flex flex-col items-center justify-center gap-3 p-4 rounded-xl border border-border bg-background transition-all ${r.border} hover:shadow-md group`}
                    >
                      <div className={`w-10 h-10 rounded-full ${r.bg} ${r.color} flex items-center justify-center group-hover:scale-110 transition-transform`}>
                        <r.icon size={20} />
                      </div>
                      <span className="text-sm font-medium">{r.label}</span>
                    </button>
                  ))}
                </div>
                <button
                  onClick={() => handleRoleSelect('Super_Admin')}
                  className="w-full mt-3 flex items-center justify-center gap-2 p-3 rounded-xl border border-border bg-background transition-all hover:border-red-500 hover:shadow-md group"
                >
                  <Crown size={16} className="text-red-500" />
                  <span className="text-sm font-medium">Super Admin Log in</span>
                </button>
              </motion.div>
            ) : (
              <motion.form
                key="login-form"
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: 20 }}
                onSubmit={handleSubmit}
                className="space-y-4"
              >
                <div className="flex items-center justify-between mb-6">
                  <div className="flex items-center gap-2 bg-muted/50 px-3 py-1.5 rounded-full border border-border">
                     {(() => {
                        const R = roles.find(r => r.id === selectedRole);
                        return (
                          <>
                            <R.icon size={14} className={R.color} />
                            <span className="text-xs font-semibold">{R.label}</span>
                          </>
                        )
                     })()}
                  </div>
                  <button 
                    type="button" 
                    onClick={() => setSelectedRole(null)}
                    className="text-xs font-medium text-muted-foreground hover:text-foreground hover:underline"
                  >
                    Change Role
                  </button>
                </div>

                {error && (
                  <div className="bg-red-500/10 text-red-500 text-sm p-3 rounded-lg border border-red-500/20 text-center">
                    {error}
                  </div>
                )}

                {selectedRole !== 'Super_Admin' && (
                  <div className="space-y-1">
                    <label className="text-sm font-medium text-muted-foreground">Tenant / Society ID</label>
                    <input 
                      type="text" 
                      name="tenantId"
                      value={credentials.tenantId}
                      onChange={handleChange}
                      required
                      placeholder="e.g. SOC123"
                      className="w-full bg-background border border-border rounded-lg px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all font-mono"
                    />
                  </div>
                )}

                <div className="space-y-1">
                  <label className="text-sm font-medium text-muted-foreground">Email</label>
                  <input 
                    type="email" 
                    name="email"
                    value={credentials.email}
                    onChange={handleChange}
                    required
                    placeholder="name@example.com"
                    className="w-full bg-background border border-border rounded-lg px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all"
                  />
                </div>

                <div className="space-y-1">
                  <div className="flex justify-between">
                    <label className="text-sm font-medium text-muted-foreground">Password</label>
                    <a href="#" className="text-xs text-primary hover:underline">Forgot password?</a>
                  </div>
                  <input 
                    type="password" 
                    name="password"
                    value={credentials.password}
                    onChange={handleChange}
                    required
                    placeholder="••••••••"
                    className="w-full bg-background border border-border rounded-lg px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-primary/50 transition-all"
                  />
                </div>

                <button 
                  type="submit" 
                  disabled={isSubmitting}
                  className="w-full bg-primary text-primary-foreground font-semibold py-3 rounded-lg hover:bg-primary/90 transition-all shadow-lg hover:shadow-primary/25 active:scale-[0.98] flex items-center justify-center gap-2 mt-4"
                >
                  {isSubmitting ? <Loader2 className="animate-spin" size={18} /> : 'Sign In'}
                </button>
              </motion.form>
            )}
          </AnimatePresence>

        </div>
      </motion.div>
    </div>
  );
};

export default Login;

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { AlertCircle, Wallet, Clock, CheckCircle2 } from 'lucide-react';
import api from '../../utils/api';

const ResidentDashboard = () => {
  const [stats, setStats] = useState({
    myComplaints: 0,
    myPendingBills: 0,
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const { data } = await api.get('/dashboard/stats');
        setStats(data);
      } catch (error) {
        console.error('Failed to load stats', error);
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  if (loading) return <div className="animate-pulse flex gap-4 h-32 w-full"><div className="flex-1 bg-muted rounded-2xl"></div></div>;

  return (
    <div className="space-y-6">
      <div>
         <h1 className="text-3xl font-bold tracking-tight">Welcome Home</h1>
         <p className="text-muted-foreground mt-1">Manage your flat, visitors, and society dues.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-card border border-border p-6 rounded-2xl glass shadow-sm flex items-center gap-4"
        >
            <div className="p-4 rounded-xl bg-orange-500/10 text-orange-500 text-orange-500">
              <Wallet size={24} />
            </div>
            <div>
              <p className="text-muted-foreground text-sm font-medium">Pending Dues</p>
              <h3 className="text-2xl font-bold text-foreground">{stats.myPendingBills} Bills</h3>
            </div>
        </motion.div>

        <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
            className="bg-card border border-border p-6 rounded-2xl glass shadow-sm flex items-center gap-4"
        >
            <div className="p-4 rounded-xl bg-blue-500/10 text-blue-500">
              <AlertCircle size={24} />
            </div>
            <div>
              <p className="text-muted-foreground text-sm font-medium">Active Complaints</p>
              <h3 className="text-2xl font-bold text-foreground">{stats.myComplaints} Open</h3>
            </div>
        </motion.div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mt-8">
         <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="bg-card border border-border p-6 rounded-2xl glass shadow-sm min-h-[300px]"
         >
            <div className="flex items-center justify-between mb-6">
               <h3 className="text-lg font-bold">Recent Complaints</h3>
               <button className="text-sm text-primary hover:underline">View All</button>
            </div>

            {stats.myComplaints === 0 ? (
               <div className="flex flex-col items-center justify-center h-40 text-muted-foreground">
                  <CheckCircle2 size={32} className="text-green-500 mb-2 opacity-50" />
                  <p>All good! No active complaints.</p>
               </div>
            ) : (
               <div className="space-y-4">
                  {/* Complaint List Mockup */}
                  <div className="flex items-center justify-between p-3 rounded-lg border border-border bg-muted/30">
                     <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-blue-500/10 text-blue-500 flex items-center justify-center"><Clock size={16}/></div>
                        <div>
                           <p className="text-sm font-medium">Water leakage in kitchen</p>
                           <p className="text-xs text-muted-foreground">Plumbing • 2 days ago</p>
                        </div>
                     </div>
                     <span className="text-xs font-semibold px-2 py-1 rounded-full bg-yellow-500/10 text-yellow-500">In Progress</span>
                  </div>
               </div>
            )}
         </motion.div>

         <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="bg-card border border-border p-6 rounded-2xl glass shadow-sm min-h-[300px]"
         >
            <div className="flex items-center justify-between mb-6">
               <h3 className="text-lg font-bold">Upcoming Visitors</h3>
               <button className="text-sm text-primary hover:underline bg-primary/10 px-3 py-1.5 rounded-lg">Pre-Approve Visitor</button>
            </div>
            <div className="flex flex-col items-center justify-center h-40 text-muted-foreground">
                 <p>No expected visitors for today.</p>
            </div>
         </motion.div>
      </div>
    </div>
  );
};

export default ResidentDashboard;

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Users, AlertCircle, Wallet, ShieldCheck, ArrowUpRight } from 'lucide-react';
import { Bar } from 'react-chartjs-2';
import api from '../../utils/api';
import 'chart.js/auto';

const SocietyAdminDashboard = () => {
  const [stats, setStats] = useState({
    totalResidents: 0,
    pendingComplaints: 0,
    todaysVisitors: 0,
    totalBillsPaid: 0,
    totalBillsPending: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const { data } = await api.get('/dashboard/stats');
        setStats(data);
      } catch (error) {
        console.error('Failed to load stats', error);
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  const chartData = {
    labels: ['Plumbing', 'Electrical', 'Housekeeping', 'Security'],
    datasets: [{
      label: 'Complaints by Category',
      data: [12, 19, 3, 5], // Example default data
      backgroundColor: 'rgba(79, 70, 229, 0.6)',
      borderRadius: 4,
    }]
  };

  const cards = [
    { title: 'Total Residents', value: stats.totalResidents, icon: Users, color: 'text-blue-500', bg: 'bg-blue-500/10' },
    { title: 'Pending Complaints', value: stats.pendingComplaints, icon: AlertCircle, color: 'text-red-500', bg: 'bg-red-500/10' },
    { title: 'Pending Bills', value: stats.totalBillsPending, icon: Wallet, color: 'text-orange-500', bg: 'bg-orange-500/10' },
    { title: 'Todays Visitors', value: stats.todaysVisitors, icon: ShieldCheck, color: 'text-green-500', bg: 'bg-green-500/10' }
  ];

  if (loading) return <div className="animate-pulse flex gap-4 h-32 w-full"><div className="flex-1 bg-muted rounded-2xl"></div></div>;

  return (
    <div className="space-y-6">
      <div>
         <h1 className="text-3xl font-bold tracking-tight">Society Overview</h1>
         <p className="text-muted-foreground mt-1">Manage everything in your society from one place.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {cards.map((card, idx) => (
          <motion.div
            key={idx}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: idx * 0.1 }}
            className="bg-card border border-border p-6 rounded-2xl glass shadow-sm flex items-center gap-4"
